import { Button, Grid, Typography, useTheme } from "@mui/material";
import React, { FunctionComponent } from "react";
import { useParams, Link } from "react-router-dom";

export const HowToVote: FunctionComponent<{}> = () => {
  const theme = useTheme();
  const params = useParams();
  const pollId = params.pollId;

  const MItem: FunctionComponent = ({ children }) =>
    <Grid xs={12} item sx={{ marginBottom: theme.spacing(3) }}>{children}</Grid>

  return (
    <Grid container>
      <Grid
        item
        xs={12}
        display="flex"
        flexDirection="column"
        alignItems="center"
        justifyContent="center"
        height={300}
        sx={{
          backgroundColor: theme.palette.secondary.main
        }}
      >
        <Typography variant="h3">How to vote</Typography>
        <Link to={`/vote/${pollId}`}>
          <Button
            variant="outlined"
            sx={{
              color: theme.palette.primary.contrastText
            }}
          >
            I already know how to vote!
          </Button>
        </Link>
        
      </Grid>

      <Grid
        container
        sx={{
          padding: theme.spacing(3)
        }}
      >
        <MItem>
          <Typography>
            You will be presented with a series of pair-wise matchups. For each matchup, you will indicate which of the two options you prefer (or if you can't decide between the two).
          </Typography>
          TODO: graphic
        </MItem>

        <MItem>
          <Typography>
            You can indicate that you prefer an option by swiping it to the right. You can also indicate that you <i>do not</i> prefer an option by swiping it to the left.
          </Typography>
        </MItem>

        <MItem>
          <Typography>
            If you are ambivalent towards both options, you can tap the middle of the screen. If you can't choose between the options because you love both of them, you can swipe right on the middle of the screen. If you do not like <i>either</i> of the options, you can swipe left on the middle of the screen.
          </Typography>
        </MItem>

        <MItem>
          <Typography>
            None of the various swiping variations are required! If you want, you can just swipe right on your choice each time. However, being more specific about your decision allows the app to break ties if need be, and can offer insight into how <i>strongly</i> the group feels about a particular option, which may be interesting to you!
          </Typography>
          
        </MItem>

        <MItem>
          <Link to={`/vote/${pollId}`}>
            <Button variant="outlined">I'm ready to vote!</Button>
          </Link>
        </MItem>
      </Grid>
    </Grid>
  );
}
