const Rating: FunctionComponent<{
  rating: number,
  possible: number,
  background: React.ReactElement,
  foreground: React.ReactElement,
}> = ({ rating, possible, foreground, background }) => {
  const partials = rating % 1;
  const wholes = rating - (partials);
  const empties = possible - Math.ceil(rating);
  const icons = [...Array(wholes)].map(() => (
    <div>
      {foreground}
    </div>
  ));

  if (partials) {
    icons.push((
      <PartialIcon
        foreground={foreground}
        background={background}
        portion={partials}
      />
    ))
  }

  if (empties) {
    for (let i = 0; i < empties; i++) {
      icons.push(
        <div>
          {background}
        </div>
      )
    }
  }

  return (
    <div
      style={{
        display: "flex"
      }}
    >
      {icons}
    </div>
  )
};

const PartialIcon: FunctionComponent<{
  background: React.ReactElement,
  foreground: React.ReactElement,
  portion: number
}> = ({
  portion,
  background,
  foreground
}) => (
  <div
        style={{ position: "relative" }}
  >
    {background}
    <div
      style={{
        position: "absolute",
        left: 0,
        top: 0,
        overflowX: "hidden",
        width: `${portion * 100}%`
      }}
    >
      {foreground}
    </div>
  </div>
);

// NOTE: this is worth testing
const OpenStatusDisplay: FunctionComponent<{
  periods: NonNullable<PlaceInfo["openingHours"]>["periods"],
}> = ({ periods }) => {
  if (!periods) {
    return (
      <>
        <Pending color="disabled" /> Open status unavailable
      </>
    )
  }

  const date = new Date();
  const day = date.getDay();
  const hour = date.getHours();
  const minutes = date.getMinutes();
  const nowMins = day * 24 * 60 + hour * 60 + minutes;

  // convert all times to mins from midnight sunday (sort)
  const times: number[] = [];
  const timeEvents = new Map<number, "open" | "close">();
  for (const p of periods) {
    if (p.open) {
      const openMins = eventMins(p.open);
      times.push(openMins);
      timeEvents.set(openMins, "open");
    }

    if (p.close) {
      const closeMins = eventMins(p.close);
      times.push(closeMins);
      timeEvents.set(closeMins, "close");
    }
  }

  // find nearest time < current time, nearest time > current time
  times.sort((a, b) => +a > +b ? 1 : -1);

  const gtIdx = times.findIndex(t => t > nowMins);
  const lteTime = times[gtIdx - 1]; // Big assume!
  if (lteTime > nowMins) {
    // alert("ASSERTION ERROR: Invalid open periods received");
    console.error({
      lteTime,
      nowMins,
      periods
    });
  }
  const gtTime = times[gtIdx];
  
  const lteEvent = timeEvents.get(lteTime)!;
  const gtEvent = timeEvents.get(gtTime)!;

  // if ltTime is open and gtTime is close, we are open
  const closed = lteEvent === "close" && gtEvent === "open";
  const open = lteEvent === "open" && gtEvent === "close";
  const tillNext = diff(nowMins, gtTime);
  const almost = tillNext < 60;

  let icon: React.ReactElement;
  let message: string;

  if (closed && almost) {
    icon = <Pending color="info" />
    message = `Opens in ${tillNext} minutes`;
  } else if (open && almost) {
    icon = <WarningAmber />
    message = `Closes in ${tillNext} minutes`;
  } else if (open) {
    icon = <CheckCircle color = "success" />
    message = "Open";
  } else if (closed) {
    icon = <Cancel color="error" />
    message = "Closed";
  } else {
    // alert("ASSERTION ERROR: INVALID OPEN STATUS");
    console.error("assertion error: open status edge case", {
      periods,
      nowMins,
      times,
      timeEvents,
      lteTime,
      gtTime,
    });
    icon = <QuestionMarkOutlined color="disabled" />;
    message = "Error calculating open status";
  }

  return (
    <>
      {icon} {message}
    </>
  );
}

const eventMins = (eventTime: {
  day: number;
  hours: number;
  minutes: number;
}): number => eventTime.day * 24 * 60 + eventTime.hours * 60 + eventTime.minutes;

const diff = (a: number, b: number) => Math.abs(a - b);