import { Choice, Poll, Ranking, Result } from "../../models";
import { Counter } from "../../common";

const head = <A = unknown>(as: A[]): A => {
  if (as.length === 0) {
    throw new Error("Assertion error: called head on empty list");
  }

  return as[0];
}

const firstPlaces = (rankings: string[][]): string[] =>
  rankings.map(head);

const counts = (options: string[]) =>
  options.reduce((counter, current) => counter.inc(current), new Counter());

const majorityWinner = (counter: Counter): [string, number] | null => {
  const results = counter.results();
  const [firstPlace, firstScore] = results[0];

  const total = results.reduce((t, [_, c]) => t + c, 0);
  const share = firstScore / total;
  if (share >= 0.5) {
    return [firstPlace, share];
  }

  return null;
}

// for all candidates, finds candidate with fewest first choice votes, or first in case of tie: Q: can choice of loser affect outcome?
const loser = (options: string[], counter: Counter): string => {
  const scores = options.map(opt =>counter.count(opt));
  const lowest = Math.min(...scores);
  const lowestIDX = scores.indexOf(lowest);

  const loser = options[lowestIDX];

  return loser;
}

const pruneLoser = (rankings: string[][], loser: string): string[][] =>
  rankings.map(r => r.filter(opt => opt !== loser));

type RankedChoiceResult = {
  winner: string;
  logs: string[];
}

const rankedChoice = (rankings: string[][], logs: string[] = []): RankedChoiceResult => {
  const options = [...new Set(rankings[0]).keys()];
  const winners = firstPlaces(rankings);
  const scores = counts(winners);
  const nextLogs = [...logs, `First place shares are: ${scores.results()}`];
  const majResult = majorityWinner(scores);
  if (majResult) {
    const [winner, share] = majResult;
    return {
      winner,
      logs: [...nextLogs, `Winner is ${winner} with ${(share * 100).toFixed(2)}% of first place rankings`],
    }
  }

  const lastPlace = loser(options, scores);
  const lastPlaceLog = `Choosing ${lastPlace} to prune`;
  const pruned = pruneLoser(rankings, lastPlace);

  return rankedChoice(pruned, [...nextLogs, lastPlaceLog]);
}

const ensureMatch = (a: string, b: string): string => {
  if (a !== b) {
    throw new Error(`Expected matching strings, got ${a} and ${b}`);
  }

  return a;
}

const mergeCounts = (a: Choice, b: Choice): Choice => ({
  optionId: ensureMatch(a.optionId, b.optionId),
  choiceTypes: Object.entries(a.choiceTypes)
    .reduce(
      (merged, [name, count]) => ({
        ...merged,
        [name]: count + b.choiceTypes[name as keyof Choice['choiceTypes']]
      }), {} as { [Property in keyof Choice['choiceTypes'] ]: number}
    )
})

const aggregateChoiceTypes = (rankings: Ranking[]): Choice[] => {
  if (rankings.length === 0) return [];
  if (rankings.length === 1) return rankings[0].choices;
  const first = rankings[0].choices;
  const rest = rankings.slice(1).map(r => r.choices);
  const agged = rest.reduce(
    (agg, current) => current.map(
      choice => mergeCounts(choice, agg.find(ch => ch.optionId === choice.optionId)!)
    ),
    first
  );

  return agged;
}

/**
 * Model: rankings: string[][]
 * winners: creates string[] list of each rankings winner
 * pickWinner: finds element with outright majority occurence in winners, null if none exists
 *  - if one is found, return them here
 * pickLoser: for all candidates, finds candidate with fewest first choice votes, or first in case of tie: Q: can choice of loser affect outcome?
 * pruneLoser: removes loser from all rankings
 * recurse
 */
export const calcResult = (poll: Poll, rankings: Ranking[]): Result<any> => {
  if (rankings.length === 0) {
    return {
      done: false,
    };
  }
  const justIDs = rankings.map(
      ranking => ranking.choices.map(
        choice => choice.optionId
      )
    );
  const result = rankedChoice(justIDs);
  console.log("calced result", result);
  const winner = poll.optionsMap[result.winner];

  const done = poll.participants
    .every(p => rankings.find(r => r.participantId === p.email));
  
  const aggregatedChoiceTypes = aggregateChoiceTypes(rankings);

  const formattedLogs = result.logs.map(
    log => poll.optionsList.reduce((fmtted, option) => fmtted.replace(option.id, option.name), log)
  );

  return {
    done, 
    winner,
    choices: aggregatedChoiceTypes,
    logs: formattedLogs,
  };
};