import decodeJWT from "jwt-decode";
import {
  PendingRanking,
  Ranking,
  Poll, 
  PendingPoll,
  Option,
  VoteStatus,
} from "../models";
import { isArray } from "lodash";

export type ClientError = {
  brand: "CLIENT_ERROR";
  status: number;
  message?: string;
};

export const isClientErr = <T extends unknown>(res: T | ClientError): res is ClientError =>
  (res as any).brand === "CLIENT_ERROR";

const clientError = (e: { status: number, message?: string }): ClientError =>
  ({
    ...e,
    brand: "CLIENT_ERROR"
  })

export class GroupthinkClient {

  private createPollEndpoint = "https://omgwtfbrblolttyl-createPollEndpoint.express.val.run";
  private readFileEndpoint = "https://omgwtfbrblolttyl-readFileEndpoint.express.val.run";
  private readGlobEndpoint = "https://omgwtfbrblolttyl-readGlobEndpoint.express.val.run";

  private writeFileEndpoint = "https://omgwtfbrblolttyl-writeFileEndpoint.express.val.run";

  private token?: string;

  async createPoll(poll: PendingPoll): Promise<Poll> {
    const res = await fetch(this.createPollEndpoint, {
      method: "POST",
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(poll),
    });
    const resBody = await res.json();

    const ownerTokenKey = this.tokenKey(resBody.id);

    console.log({ owner: resBody.owner, token: resBody.owner.token, ownerTokenKey });

    localStorage.setItem(ownerTokenKey, resBody.owner.token);

    return resBody;
  }

  async getPollWithTokens(pollID: string): Promise<Poll | ClientError> {
    const token = await this.getToken(pollID);
    if (!token) {
      throw new Error(`Unable to resolve access token for poll ${pollID}`);
    }

    const { email } = this.decodeToken(token);
    const url = `${this.readFileEndpoint}?path=/polls/${pollID}/owner/poll.json`;

    const res = await fetch(url, {
      headers: {
        token,
      }
    });

    if (!res.ok) {
      return clientError({
        status: res.status,
        message: (await res.json()).msg
      });
    }

    const body = await res.json();

    return JSON.parse(body.file);
  }

  async getPollWithRankings(pollID: string): Promise<Poll> {
    const accessToken = this.getToken(pollID);
    if (!accessToken) {
      throw new Error(`Unable to resolve access token for poll ${pollID}`);
    }
    const glob = `/polls/${pollID}/participants/**.json`; // should get root poll.json and all users rankings
    const url = `${this.readGlobEndpoint}?glob=${glob}`;
    const res = await fetch(url, {
      headers: {
        token: accessToken
      }
    });

    const body = await res.json();
    if (!body || !isArray(body) || body.length === 0) {
      throw new Error("Could not fetch poll with rankings");
    }

    const pollFile = body.find(file => (file.path as string).endsWith("poll.json"));
    if (!pollFile) {
      throw new Error("Did not recieve poll!");
    }

    // BOOKMARK: get all files that match ranking pattern
    // send user email as userID in ranking
    const rankingFiles = body.filter(
      file => (file.path as string).startsWith(`/polls/${pollID}/participants/rankings`)
    );

    const poll = JSON.parse(pollFile.file);
    const rankings = rankingFiles.map(rf => JSON.parse(rf.file));

    const withOptionsMap = this.buildOptionsMap(poll);
    const withVoteStatuses = this.setStatuses(withOptionsMap, rankings);

    return {
      ...withOptionsMap,
      rankings,
    };
  }

  async getPoll(pollId: string): Promise<Poll | null> {
    const accessToken = this.getToken(pollId);
    if (!accessToken) throw new Error("No access token found for poll: " + pollId);

    const url = `${this.readFileEndpoint}?path=/polls/${pollId}/participants/poll.json`;

    const res = await fetch(url, {
      headers: { "token": accessToken }
    });

    const { file } = await res.json();
    const poll = JSON.parse(file);

    const withOptionsMap = this.buildOptionsMap(poll);

    return withOptionsMap;
  }

  async createRanking(pending: PendingRanking): Promise<Ranking> {
    const accessToken = this.getToken(pending.pollId);
    if (!accessToken) throw new Error("No token found for poll: " + pending.pollId);

    const { email } = this.decodeToken(accessToken);

    const withEmail = {
      ...pending,
      participantId: email
    };

    const res = await fetch(this.writeFileEndpoint, {
      method: "POST",
      headers: { "token": accessToken },
      body: JSON.stringify({
        file: JSON.stringify(withEmail),
        path: `/polls/${pending.pollId}/participants/rankings/${email}.json`,
      }),
    });

    const resBody = await res.json();

    return resBody as Ranking;
  }

  public userInfo(pollID: string): { email: string } | null {
    const token = this.getToken(pollID);
    if (!token) return null;

    return this.decodeToken(token);
  }

  buildOptionsMap(poll: Poll): Poll {
    return ({
      ...poll, 
      optionsMap: poll.optionsList
        .reduce(
          (acc: Record<string, Option<any>>, opt: any) => ({ ...acc, [opt.id]: opt }),
        {})
    });
  }

  setStatuses(poll: Poll, rankings: Ranking[]): Poll {
    return {
      ...poll,
      participants: poll.participants.map(
        participant => ({
          ...participant,
          status: !!rankings.find(r => r.participantId === participant.email) ? VoteStatus.Decided : VoteStatus.Undecided
        })
      )
    }
  }

  getToken(pollId: string): string | null {
    if (this.token) {
      return this.token;
    }
    const params = new URLSearchParams(window.location.search);
    const fromQuery = params.get("token");

    const tokenKey = this.tokenKey(pollId);

    if (fromQuery) {
      console.log("Setting token for poll from query string", pollId, fromQuery);
      localStorage.setItem(tokenKey, fromQuery);
      this.token = fromQuery;

      return fromQuery;
    }

    const fromLocal = localStorage.getItem(tokenKey);
    if (fromLocal) {
      console.log("Retrieved key from local storage");
      this.token = fromLocal;
      return fromLocal;
    }

    console.log(`Unable to locate token for poll with id: ${pollId}`)

    return null;
  }

  logId(): number {
    const lastIdRes = localStorage.getItem("log_id");
    const lastId = lastIdRes ? parseInt(lastIdRes) : 0;
    const newId = lastId + 1;
    localStorage.setItem("log_id", newId.toString());

    return newId;
  }

  tokenKey(pollId: string): string {
    return `groupthink_token:${pollId}`;
  }

  decodeToken(token: string): { email: string } {
    const decoded = decodeJWT(token) as any;
    console.log("decoded token", { decoded });
    if (typeof decoded !== "object" || typeof decoded?.meta?.email !== "string") {
      throw new Error("Recieved malformed token");
    }

    return {
      email: decoded.meta.email,
    }
  }

  async log(pollID: string, msg: string, context = {}): Promise<void> {
    const token = this.getToken(pollID);
    if (!token) {
      console.error("Unable to log to backend while unauthenticated", {
        msg, context
      });
      return;
    }

    const decoded = this.decodeToken(token);

    const createdAt = new Date().toISOString();

    const serialized = JSON.stringify({
      msg,
      createdAt,
      context: {
        userEmail: decoded.email,
        ...context
      }
    });

    const res = await fetch(this.writeFileEndpoint, {
      method: "POST",
      headers: { token },
      body: JSON.stringify({
        file: serialized,
        path: `/polls/${pollID}/logs/${decoded.email}/${this.logId()}.json`
      })
    });

  }

}
