import React, { FunctionComponent, useEffect, useState } from "react";
import { useParams, useSearchParams } from "react-router-dom";
import { Alert, AlertTitle, Button, CircularProgress, Divider, FormControlLabel, Grid, Link, Radio, RadioGroup, Stack, Typography, useTheme } from "@mui/material";
import { GroupthinkClient } from "../../client/groupthink";
import { Choice, Poll, Ranking, Result } from "../../models";
import { Participant } from "../../components/participant";
import { RankedChoice } from "../../components/ranked-choice";
import { ChoiceBreakdown, choiceBreakdowns, ChoiceReport } from "../../stats";
import { rankedChoice, averagePlacement } from "../../logic/ranking";
import { Layout } from "../../components/layout";
import { Spinner } from "../../components/spinner";

type RankingDisplay = { name: string; choices?: Choice[] };
enum AlgType {
  RANKED_CHOICE = "RANKED_CHOICE",
  AVERAGE_PLACEMENT = "AVERAGE_PLACEMENT"
}

const groupthink = new GroupthinkClient();

export const PollRoute: FunctionComponent = () => {
  const theme = useTheme();
  const params = useParams();
  const pollId = params.pollId;
  // TODO: handle pollID missing

  const [poll, setPoll] = useState<Poll | null>(null);
  const [breakdowns, setBreakdowns] = useState<ChoiceReport | null>(null);
  const [rankingView, setRankingView] = useState<string>("RESULTS");
  const [ranking, setRanking] = useState<RankingDisplay | null>(null);
  const [algorithm, setAlgorithm] = useState<AlgType>(AlgType.RANKED_CHOICE);
  const [result, setResult] = useState<Result<any> | null>(null);

  /**
   * SET RANKING DISPLAY
   */
  useEffect(() => {
    if (!poll || !result) return;
    if (rankingView === "RESULTS") {
      setRanking({
        name: "Overall ranking",
        choices: result.choices
      });
    } else {
      const ranking = poll.rankings.find(r => r.participantId === rankingView);
      if (!ranking) {
        alert(`Can't find ranking for participant ${rankingView}`);
        return;
      }

      const participant = poll.participants.find(p => p.email === rankingView);
      setRanking({
        name: `${participant?.name}'s ranking`,
        choices: ranking.choices
      });
    }
  }, [rankingView, poll, result]);

  useEffect(() => {
    if (!(poll?.rankings.length)) {
      return;
    }

    const bd = choiceBreakdowns(poll.rankings);
    setBreakdowns(bd);
  }, [poll]);

  useEffect(() => {
    if (!poll?.rankings)  {
      return;
    }
    switch (algorithm) {
      case AlgType.RANKED_CHOICE:
        const rc = rankedChoice(poll, poll.rankings);
        setResult(rc);
        break;
      case AlgType.AVERAGE_PLACEMENT:
        const ap = averagePlacement(poll, poll.rankings);
        setResult(ap);
        break;
    }
  }, [algorithm, poll]);

  useEffect(() => {
    const getPoll = async () => {
      if (!pollId) return;
      
      const pollRes = await groupthink.getPollWithRankings(pollId);

      if (!pollRes) {
        alert("poll not found");
        return;
      }
      setPoll(pollRes);
    };
    getPoll();
  }, [pollId]);

  if (!poll) {
    return <Spinner message="Loading poll" />
  }

  const title = ranking?.name ? (
    `${ranking.name}`
  ) : (
    <>Results</>
  );

  const remainingCount = poll.participants.length - (poll.rankings?.length || 0);

  const resultMsg = result !== null ? 
    `The ${result?.done ? "final result" : "current result"} is ${result?.winner ? result.winner.name : " a tie between " + result?.tie?.map(opt => opt.name).join(", ")}` :
    "No votes sumbitted"

  if (!pollId) {
    return <Alert severity="error">
      Could not find poll
    </Alert>
  }
  const userInfo = groupthink.userInfo(pollId);
  const userHasVoted = !!(userInfo!.email && poll.rankings.find(r => r.participantId === userInfo!.email));

  return (
    <Layout>
      <Stack
        spacing={theme.spacing(3)}
        sx={{ pb: theme.spacing(4) }}
      > {/* TODO: set vertical spacing  */}
        <Grid item xs={12}>
          <Typography variant="h3">
            {poll.name}
          </Typography>
          <Typography variant="subtitle1">
            by {poll.owner.name}
          </Typography>
          <Typography variant="subtitle2">
            {poll.participants.length} participants
          </Typography>
          {!userHasVoted ? <></> :
          result?.done ? (
            <Alert severity="success">
              <AlertTitle>Complete</AlertTitle>
              The results are in! Check them out below...
            </Alert>
          ) : (
            <Alert severity="warning">
              <AlertTitle>In progress</AlertTitle>
              We are still wating on {remainingCount} participants to submit their votes
            </Alert>
          )}
        </Grid>

        {userHasVoted ? (
          <>
            <Grid item xs={12}>
              <RadioGroup
                onChange={e => {
                  setAlgorithm(e.target.value as AlgType)
                }}
                value={algorithm}
                defaultChecked
              >
                <FormControlLabel
                  label="Ranked Choice"
                  value={AlgType.RANKED_CHOICE}
                  control={<Radio />}
                  key="ranked-choice"
                />
                <FormControlLabel
                  label="Average Placement"
                  value={AlgType.AVERAGE_PLACEMENT}
                  control={<Radio />}
                  key="averageplacement"
                />
              </RadioGroup>
            </Grid>

            <Grid item xs={12}>
              <Typography variant="h3">
                  {title}
                </Typography>
                <h3>{resultMsg}</h3>
            </Grid>

            <Grid item xs={12}>
              <RadioGroup
                onChange={e => setRankingView(e.target.value)}
                value={rankingView}
                defaultChecked={true}
              >
                <FormControlLabel
                  label="Results"
                  control={<Radio />}
                  value="RESULTS"
                  key="RESULTS"
                />
                {poll.participants.map(
                  p => (
                    <FormControlLabel
                      label={`${p.name}'s ranking`}
                      control={<Radio />}
                      value={p.email}
                      key={p.email}
                      disabled={!!!poll.rankings.find(r => r.participantId === p.email)}
                    />
                  )
                )}
              </RadioGroup>
            </Grid>
            
            {ranking?.choices && (
              <Stack
                spacing={theme.spacing(1)}
              >
                {ranking.choices.map((ch, i) => (
                  <RankedChoice
                    key={ch.optionId}
                    option={poll.optionsMap[ch.optionId]}
                    choice={ch}
                    winner={
                      result?.winner?.id === ch.optionId ||
                      !!result?.tie?.find(opt => opt.id === ch.optionId)
                    } 
                    breakdown={breakdowns?.[ch.optionId]}
                  />
                ))}
              </Stack>
            )}
            <Grid item xs={12}>
              {result?.logs && (
                <>
                  <Typography component="h2">
                    {algorithm === AlgType.RANKED_CHOICE ? "Ranked choice" : "Average placement"} explanation
                  </Typography>
                  <Stack>
                    {result.logs.map(
                      (log, idx) => <Typography variant="body2">{idx+1}. {log}</Typography>
                    )}
                  </Stack>
                </>
                
              )}
            </Grid>
          </>
        ) : (
          <Grid xs={12}>
            <Alert severity="warning">
              To view the results of this poll, cast your vote! <Link href={`${process.env.REACT_APP_GROUPTHINK_URL}#/vote/${pollId}`} target="_blank">Vote here!</Link>
            </Alert>
          </Grid>
        )}
      </Stack>
    </Layout>
  );
}
