import React, { FunctionComponent, useState } from "react";
import {
  Grid,
  Typography,
  Link,
  Button,
  Card,
  Paper,
  CardContent,
  CardActions,
  CardMedia,
  Icon,
  Dialog,
  useTheme,
  Stack,
} from "@mui/material";
import { PlacesInfo } from "./places-info";
import { Option as OptionProps, OptionType } from "../../models";
import { Info } from "@mui/icons-material";

export type Props = Partial<OptionProps<any>>;

// TODO: make generic?
export const Option: FunctionComponent<Props> = ({
  name,
  img,
  uri,
  description,
  info,
  type,
}) => {
  const theme = useTheme();
  const [infoOpen, setInfoOpen] = useState(false);
  console.log({ info });

  return (
    <div
      style={{
        padding: theme.spacing(2),
        width: "300px" // TODO: how do i make sure this doesnt clash with outer widths/paddings/margsin?
      }}
    >
      <Card
        component={Paper}
        elevation={3}
      >
        {
          img && (
            <CardMedia
              component="img"
              image={img}
              height="140" // Bookmark: aybe causing problems?
            />
          )
        }
        
        <CardContent>
          <Grid container>
            <Grid item xs={12}>
              <Typography variant="h5" component="div">{name}</Typography>
              <Typography variant="body2" color="text.secondary">
                {description}
              </Typography>
            </Grid>
          </Grid>
        </CardContent>
        <CardActions>

          {uri && (
            <Button size="small" href={uri} target="_blank">
              link icon
            </Button>
          )}
          {
            info && Object.keys(info).length > 0 && (
              <Info onClick={() => setInfoOpen(true)} />
            )
          }
        </CardActions>
      </Card>
      <Dialog
        open={infoOpen}
        onClose={() => setInfoOpen(false)}
      >
        {resolveInfoRenderer(type)({ info })}
      </Dialog>
    </div>
  );
}

interface InfoProps {
  info: OptionProps<any>["info"];
}

const DefaultInfo: FunctionComponent<InfoProps> = ({ info }) => {
  const theme = useTheme();
  return (
    <Stack
      spacing={theme.spacing(2)}
      style={{
        padding: theme.spacing(4)
      }}
    >
      {Object.entries(info).map(([k, v]) => (
        
          <Typography variant="body2">
            {k}: {v}
          </Typography>
      ))}
    </Stack>
  );
}

const resolveInfoRenderer = (itemType?: OptionType) => {
  switch (itemType) {
    case OptionType.GOOGLE_PLACE:
      return PlacesInfo;
    default:
      return DefaultInfo;
  }
}
