import { Poll } from "../models";

export type EmailInvite = {
  mailto: string;
  subject: string;
  name: string;
  body: string;
  link: string;
}

const groupthinkURL = process.env["REACT_APP_GROUPTHINK_URL"];
if (!groupthinkURL) {
  throw new Error("MISSING REACT_APP_GROUPTHINK_URL");
}

const fmtList = (items: string[]): string => {
  switch (items.length) {
    case 0:
      return "";
    case 1:
      return items[0];
    case 2:
      return `${items[0]} and ${items[1]}`;
    default:
      return `${items[0]}, ${fmtList(items.slice(1))}`;
  }
}

export const createEmailInvitations = (poll: Poll): EmailInvite[] => {
  const missingTokens = poll.participants.filter(p => !!!p.token);
  if (missingTokens.length) {
    alert(`Missing tokens for ${missingTokens.length} participants`);
  }

  const invites = poll.participants.map(
    participant => {
      const href = `${groupthinkURL}?token=${participant.token}#/${poll.id}`;
      const subject = `${participant.name}! ${poll.owner.name} wants your help deciding ${poll.name}`;

      return ({
        mailto: participant.email,
        name: participant.name,
        subject,
        link: href,
        body:
`Join ${poll.owner.name} in deciding ${poll.name}!
${poll.description || poll.description}
Click or copy the link below to join! (if possible, open this in a new browser tab)
${href}
`
      });
    });
  
  return invites;
};
