import { gte } from "lodash";
import { Choice, Option, Poll, Ranking } from "../../models";
import { addObj, maxBy, minBy, sentiment } from "./common";


const avgPlacement = (option: Option<any>, rankings: Ranking[]) => {
  const places = rankings.map(r => r.choices.findIndex(ch => ch.optionId === option.id));
  const avg = places.reduce((total, current) => total + current, 0) / rankings.length;

  return avg;
};

const aggregateChoiceTypes = (opt: Option<any>, rankings: Ranking[]): Choice["choiceTypes"] => {
  const ranks = rankings.map(r => r.choices.find(ch => ch.optionId === opt.id)!);
  if (ranks.length === 0) {
    console.error("Assertion failed, recieved 0 rankings", { opt, ranks, rankings });
    throw new Error("Assertion failed, recieved 0 rankings");
  }

  if (ranks.length === 1) {
    return ranks[0].choiceTypes;
  }

  const first = ranks[0].choiceTypes;
  const rest = ranks.slice(1).map(({ choiceTypes }) => choiceTypes);
  const agged = (rest as Record<string, number>[]).reduce(
    (acc, curr) => addObj(acc, curr), first
  ) as Choice["choiceTypes"];


  return agged;
}

const printVibes = (vibes: Choice["choiceTypes"]): string =>
  Object.entries(vibes).map(([ key, val ]) => `${key}: ${val}`).join(", ");
export const calcResult = (poll: Poll, rankings: Ranking[]) => {
  const aggregatedChoices = poll.optionsList.map(
    opt => ({
      participantId: "OVERALL_RESULTS",
      optionId: opt.id,
      choiceTypes: aggregateChoiceTypes(opt, rankings)
    })
  );
  const done = poll.participants.every(
    p => rankings.find(r => r.participantId === p.email)
  );
  const logs: string[] = [];
  const avgs = poll.optionsList.map(
    opt => avgPlacement(opt, rankings)
  );

  logs.push(
    `Average placements are ${avgs.map((avg, i) => poll.optionsList[i].name + `: ${(avg + 1).toFixed(2)}`).join(", ")}`
  )

  const bestAvgResult = Math.min(...avgs);
  const winners = poll.optionsList.filter((opt, idx) => avgs[idx] <= bestAvgResult);
  if (winners.length === 1) {
    const winner = winners[0];
    logs.push(`${winner.name} wins by having the best average placement of ${(bestAvgResult + 1).toFixed(2)}`);

    return {
      winner: winner,
      choices: aggregatedChoices,
      logs,
      done
    }
  }

  /**
   * TODO: minBy, maxBy are broken, also stupid
   */
  const vibes = winners!.map(opt => aggregateChoiceTypes(opt, rankings)) as Choice["choiceTypes"][];
  console.log({ vibes });
  const printedVibes = vibes?.map((v, i) => `${winners[i].name}: ${printVibes(v)}`);
  console.log(printedVibes);
  const joinedVibes = printedVibes.join(", ");
  logs.push(`Best average placement was a tie between ${winners.map(w => w.name).join(", ")}`);
  for (const pv of printedVibes) {
    console.log("PUSHING", pv)
    logs.push(pv);
  }
  
  const calcedVibes = vibes.map(v => sentiment(v));
  const winsResult = maxBy((_, idx) => calcedVibes[idx].winExplicitness, winners);

  if (winsResult.winner) {
    logs.push(`Tie broken by highest win explicitness, ${winsResult.winner.name} wins`);

    return {
      winner: winsResult.winner,
      choices: aggregatedChoices,
      logs,
      done,
    };
  }

  logs.push(`Still a tie between ${winsResult.tie!.map(t => t.name).join(", ")}`);
  logs.push("Breaking tie by loss types");

  const lossesResult = minBy((_, idx) => calcedVibes[idx].lossExplicitness, winsResult.tie!);

  if (lossesResult.winner) {
    logs.push(`Tie broken by lowest loss explicitness, ${lossesResult.winner} wins`);

    return {
      winner: lossesResult.winner,
      choices: aggregatedChoices,
      logs,
      done,
    };
  };

  logs.push(`Still a tie between ${lossesResult.tie!.map(t => t.name).join(", ")}`);

  return {
    tie: lossesResult.tie,
    logs,
    choices: aggregatedChoices,
    done
  };
};
