import React, { FunctionComponent, useCallback, useState } from "react";
import { Box, SxProps, Typography } from "@mui/material";
import { Menu } from "@mui/icons-material";
import { useTheme } from "@mui/material/styles";
import { Navigate, useNavigate } from "react-router-dom";

export interface Props {
  children?: React.ReactNode;
}

const menuBaseStyle: SxProps = {
  position: "absolute",
  right: "6%",
  top: "50%",
  transform: "translate(0%, -50%)",
};

const headerHeight = "48px";

export const Layout: FunctionComponent<Props> = ({ children }) => {
  const theme = useTheme();
  const [menuOpen, setMenuOpen] = useState(false);
  const navigate = useNavigate();

  const returnHome = useCallback(() => {
    const yes = window.confirm("Return home (if you are creating a poll you will lose your progress)?");
    if (yes) {
      navigate("/");
    }
  }, []);

  return (
    <Box>
      <Box
        sx={{
          width: "100vw",
          height: headerHeight,
          position: "fixed",
          backgroundColor: theme.palette.background.paper
        }}
      >
        <Box
          sx={{
            minWidth: "100%",
            minHeight: "100%",
            position: "relative",
          }}
        >

          <Typography
            component="h1"
            sx={{
              position: "absolute",
              left: "6%",
              top: "50%",
              transform: "translate(0%, -50%)"
            }}
            onClick={returnHome}
          >
            <span style={{ color: theme.palette.primary.main }}>group</span>think
          </Typography>

          <Menu
            onClick={() => setMenuOpen(!menuOpen)}
            sx={{
              ...menuBaseStyle,
              color: menuOpen ? theme.palette.primary.dark : theme.palette.primary.light
            }}
          />
    
        </Box>
      </Box>
      
      <Box
        sx={{
          margin: theme.spacing(0, 4, 0, 4),
          boxSizing: "border-box"
        }}
      >
        <Box sx={{ height: headerHeight }}></Box>
        {children}
      </Box>
    </Box>
  )
};
