import { OptionType, PendingOption } from "../models";
import * as gt from "./google-types";

const cleanTitle = (unclean: string): string => {
  const parts = unclean.split(/[(|]/);

  return parts[0];
}

const itemToOption = (item: gt.Item): PendingOption<gt.Item> => ({
  name: cleanTitle(item.title),
  uri: item.link,
  description: item.snippet,
  img: item.pagemap?.cse_image?.[0]?.src, // TODO: Default
  original: item,
  type: OptionType.GOOGLE_SEARCH_RESULT,
})

export class GoogleSearchClient {
  private token: string;
  private url: string;
  constructor(token = process.env.REACT_APP_GOOGLE_API_KEY || process.env.REACT_APP_GOOGLE_PROXY_KEY) {
    if (process.env.NODE_ENV === "production") {
      const token = process.env.REACT_APP_GOOGLE_API_KEY;
      if (!token) {
        throw new Error("MISSING REACT_APP_GOOGLE_API_KEY");
      }
      this.url = "https://www.googleapis.com/customsearch/v1";
      this.token = token;
      return;
    } else if (process.env.NODE_ENV === "development") {
      const token = process.env.REACT_APP_GOOGLE_PROXY_KEY;
      if (!token) {
        throw new Error("MISSINGREACT_APP_GOOGLE_PROXY_KEY");
      }
      this.url = "https://omgwtfbrblolttyl-googleProxy.express.val.run";
      this.token = token;
      return;
    }

    throw new Error(`Unknown NODE_ENV: ${process.env.NODE_ENV}`);
  }

  async search(term: string, start = 0) {
    const caviarCx = "6bb8b229698a51c79"; // NOTE: we will have multiple ctx's in the future
    const url = `${this.url}?key=${this.token}&cx=${caviarCx}&q=${term}&start=${start}`;

    const res = await fetch(url);
    const json = await res.json();

    const mapped = json.items.map((item: gt.Item) => itemToOption(item));

    return { items: mapped as PendingOption[] };
  }
}

const googleSearch = new GoogleSearchClient();

export default googleSearch;
