// vibe calcing, min/max choosing, tie breaking
// validation of rankings+poll (all accounted for etc)

import { Choice } from "../../models";

type Comparitor = { id: number, fn: (a: number, b: number) => number };
type SuperlativeResult<T> = {
  winner?: T;
  tie?: T[];
}

const gte: Comparitor = { id:-Infinity, fn: (a, b) => a >= b ? a : b };
const lt: Comparitor = { id: Infinity, fn: (a, b) => a < b ? a : b };

const findIDXes = <T = unknown>(elem: T, elems: T[]): number[] =>
  elems.reduce((acc, curr, idx) => curr === elem ? [...acc, idx] : acc, [] as number[]);

const superlativeBy = <T = unknown>(
  prop: (item: T, idx: number) => number,
  comp: Comparitor,
  items: T[]
): SuperlativeResult<T> => {
  if (items.length === 0) {
    throw new Error("Assertion: cannot choose superlative from empty list");
  }
  const scores = items.map((item, idx) => prop(item, idx));
  const superlative = scores.reduce(comp.fn, comp.id);
  const tieIDXs = findIDXes(superlative, scores);

  if (tieIDXs.length === 1) {
    return {
      winner: items[0]
    };
  }

  return {
    tie: tieIDXs.map(idx => items[idx])
  };
};

export const minBy = <T = unknown>(fn: (item: T, idx: number) => number, items: T[]) => superlativeBy(fn, lt, items);
export const maxBy = <T = unknown>(fn: (item: T, idx: number) => number, items: T[]) => superlativeBy(fn, gte, items);

export const sentiment = (choiceTypes: Choice["choiceTypes"]) => {
  const {
    explicitWins,
    positiveTies,
    implicitWins,
    negativeTies,
    explicitLosses,
    implicitLosses,
  } = choiceTypes;

  const totalWins =
    explicitWins +
    implicitWins +
    positiveTies;
  const winExplicitness = explicitWins / totalWins;

  const totalLosses =
    explicitLosses + 
    implicitLosses + 
    negativeTies;
  
  const lossExplicitness = explicitLosses / totalLosses;

  return {
    winExplicitness,
    lossExplicitness
  };
};

// Will contain all fiels in a summed with any matching fields in B
export const addObj = <T extends Record<string, number>>(a: T, b: T): Record<string, number> =>
  Object.entries(a)
    .reduce((summed, [key, val]) => ({
      ...summed,
      [key]: val + (b[key] || 0)
    }), {});
