import { assert } from "console";
import { Option } from "../../models";

export type SearchStepResult<T> = {
  choiceA: T;
  choiceB: T;
}

type InsertionIdx = number;
type WinnerId = string | undefined;

export type SortStepResult<T> = SearchStepResult<T> & {
  progress: number;
}

export function* insertIdx2<T extends { id: string }>(
  opt: T,
  opts: T[],
  low = 0,
  high = opts.length - 1
): Generator<SearchStepResult<T>, InsertionIdx, WinnerId> {
  while (low <= high) {
    const mid = Math.floor((low + (high - low) / 2));
    const winner = yield { choiceA: opts[mid], choiceB: opt };
    const optIsGT = winner === opt.id;
    const optIsLT = winner === opts[mid].id;

    if (!optIsGT && !optIsLT) {
      return mid;
    } if (optIsGT) {
      low = mid + 1;
    } else if (optIsLT) {
      high = mid - 1;
    } else {
      throw new Error("Assertion error: comparison must be < > or =");
    }
  }

  return low;
}

export function* insertIdx<T extends { id: string }>(
  opt: T,
  opts: T[],
  low = 0,
  high = opts.length - 1,
): Generator<SearchStepResult<T>, InsertionIdx, WinnerId> {
  console.log(`insert idx: low ${low}, high ${high}, opt: ${opt.id}`);
  if (opts.length === 0) {
    console.log(`insertIDX: empty opts, insert at 0`)
    return 0;
  }

  if (low === high) { // BOOKMARK: maybe this needs to be >=? OR this is just doing an extra matchup
    console.log("insertIDX: low === high", `comparing ${opts[low].id} and ${opt.id}`);
    const winner = yield { choiceA: opts[low], choiceB: opt };
    const optIsGT = winner === opt.id;

    if (optIsGT) {
      console.log("insertIDX: opt wins, low+1")
      return low + 1;
    }

    console.log("insertIDX: opt loses, low")
    return low;
  }

  const mid = Math.floor((low + high) / 2);
  console.log("insertIDX:", { low, mid, high });
  const candidate = opts[mid];
  const winner = yield { choiceA: opt, choiceB: candidate };
  console.log(`insertIDX: winner is ${ winner }`);
  const optIsGT = winner === opt.id;
  const optIsLT = winner === candidate.id;

  if (optIsGT) {
    const idx = yield* insertIdx(opt, opts, mid + 1, high);
    return idx;
  }

  if (optIsLT) {
    const idx = yield* insertIdx(opt, opts, low, mid) // BOOKMARK: maybe broken
    return idx;
  }

  console.log(`tie`);
  return mid;
}

export function* insertionSort<T extends { id: string }>(opts: T[]): Generator<SortStepResult<T>, T[], WinnerId> {
  const unsorted = [...opts];
  const sorted: T[] = [];

  let winnerId: WinnerId = undefined;
  while (unsorted.length > 0) {
    const toInsert = unsorted.pop()!;
    console.log("sort: inserting", toInsert.id);
    const search = insertIdx2(toInsert, sorted);
    while (true) {
      const step = search.next(winnerId);
      if (step.done) {
        console.log("sort: insert idx found", step.value);
        sorted.splice(step.value, 0, toInsert);
        break;
      } else {
        winnerId = yield { ...step.value, progress: sorted.length / opts.length };
        console.log("sort: winner is", winnerId);
      }
    }
  }

  return sorted.reverse();
}
