import React, { FunctionComponent } from "react";
import { Box, CircularProgress, Stack, Typography, useTheme } from "@mui/material";

export interface Props {
  message?: string;
}

export const Spinner: FunctionComponent<Props> = ({ message }) => {
  const theme = useTheme();
  return (
    <Box
      style={{
        width: "100%",
        height: "100%",
        display: "flex",
        justifyContent: "center",
        alignItems: "center"
      }}
    >
      <Box
        style={{
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          alignItems: "center"
        }}
      >
        <CircularProgress size={80} style={{ marginBottom: theme.spacing(2) }} />
        {message && (
          <Typography variant="h5">{message}</Typography>
        )}
      </Box>
    </Box>
  );
}
